import android.content.Context
import android.content.SharedPreferences
import java.security.SecureRandom
import java.util.UUID
import javax.crypto.Mac
import javax.crypto.spec.SecretKeySpec

class SessionTokenGenerator(context: Context) {
    
    private val prefs: SharedPreferences = context.getSharedPreferences(
        "session_prefs",
        Context.MODE_PRIVATE
    )
    
    private val secureRandom = SecureRandom()
    
    private val sessionKey: String by lazy {
        prefs.getString(SESSION_KEY, null) ?: generateAndStoreSessionKey()
    }
    
    companion object {
        private const val SESSION_ID_KEY = "session_id"
        private const val SESSION_KEY = "session_key"
        private const val SESSION_TIMESTAMP = "session_timestamp"
        private const val TOKEN_LENGTH = 32
        private const val ALPHANUMERIC = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"
        private const val SESSION_TIMEOUT_MS = 24 * 60 * 60 * 1000L // 24 hours
    }
    
    fun getOrCreateSessionId(): String {
        val existingSessionId = prefs.getString(SESSION_ID_KEY, null)
        val sessionTimestamp = prefs.getLong(SESSION_TIMESTAMP, 0L)
        val currentTime = System.currentTimeMillis()
        
        return if (existingSessionId != null && 
                   (currentTime - sessionTimestamp) < SESSION_TIMEOUT_MS) {
            existingSessionId
        } else {
            createNewSession()
        }
    }
    
    private fun createNewSession(): String {
        val sessionId = UUID.randomUUID().toString()
        prefs.edit().apply {
            putString(SESSION_ID_KEY, sessionId)
            putLong(SESSION_TIMESTAMP, System.currentTimeMillis())
            apply()
        }
        return sessionId
    }
    
    fun generateTemporaryToken(): String {
        val randomBytes = ByteArray(TOKEN_LENGTH)
        secureRandom.nextBytes(randomBytes)
        
        return buildString(TOKEN_LENGTH) {
            for (byte in randomBytes) {
                val index = (byte.toInt() and 0xFF) % ALPHANUMERIC.length
                append(ALPHANUMERIC[index])
            }
        }
    }
    
    fun generateSecureToken(sessionId: String): String {
        val timestamp = System.currentTimeMillis().toString()
        val nonce = generateNonce()
        val data = "$sessionId:$timestamp:$nonce"
        
        return try {
            val hmac = Mac.getInstance("HmacSHA256")
            val secretKey = SecretKeySpec(sessionKey.toByteArray(), "HmacSHA256")
            hmac.init(secretKey)
            val hash = hmac.doFinal(data.toByteArray())
            
            bytesToAlphanumeric(hash, TOKEN_LENGTH)
        } catch (e: Exception) {
            generateTemporaryToken()
        }
    }
    
    private fun generateNonce(): String {
        val nonceBytes = ByteArray(16)
        secureRandom.nextBytes(nonceBytes)
        return bytesToHex(nonceBytes)
    }
    
    private fun bytesToAlphanumeric(bytes: ByteArray, length: Int): String {
        return buildString(length) {
            for (i in 0 until length) {
                val index = (bytes[i % bytes.size].toInt() and 0xFF) % ALPHANUMERIC.length
                append(ALPHANUMERIC[index])
            }
        }
    }
    
    private fun bytesToHex(bytes: ByteArray): String {
        return bytes.joinToString("") { "%02x".format(it) }
    }
    
    private fun generateAndStoreSessionKey(): String {
        val keyBytes = ByteArray(32)
        secureRandom.nextBytes(keyBytes)
        val key = bytesToHex(keyBytes)
        prefs.edit().putString(SESSION_KEY, key).apply()
        return key
    }
    
    fun invalidateSession() {
        prefs.edit().apply {
            remove(SESSION_ID_KEY)
            remove(SESSION_TIMESTAMP)
            apply()
        }
    }
    
    fun isSessionValid(): Boolean {
        val sessionTimestamp = prefs.getLong(SESSION_TIMESTAMP, 0L)
        val currentTime = System.currentTimeMillis()
        return (currentTime - sessionTimestamp) < SESSION_TIMEOUT_MS
    }
    
    fun refreshSession() {
        val sessionId = prefs.getString(SESSION_ID_KEY, null)
        if (sessionId != null) {
            prefs.edit().putLong(SESSION_TIMESTAMP, System.currentTimeMillis()).apply()
        } else {
            createNewSession()
        }
    }
}

class SessionManager(context: Context) {
    
    private val tokenGenerator = SessionTokenGenerator(context)
    private val activeTokens = mutableSetOf<String>()
    
    fun initializeSession(): String {
