    }
    
    fun generateApiToken(): String {
        val token = tokenGenerator.generateTemporaryToken()
        activeTokens.add(token)
        return token
    }
    
    fun generateSecureApiToken(): String {
        val sessionId = tokenGenerator.getOrCreateSessionId()
        val token = tokenGenerator.generateSecureToken(sessionId)
        activeTokens.add(token)
        return token
    }
    
    fun invalidateToken(token: String) {
        activeTokens.remove(token)
    }
    
    fun clearAllTokens() {
        activeTokens.clear()
    }
    
    fun endSession() {
        clearAllTokens()
        tokenGenerator.invalidateSession()
    }
    
